// Combine webhook body with verse data
const webhook = $('Webhook: New Lesson').first().json.body;
const verse = $input.first().json;
const verseData = Array.isArray(verse) ? verse[0] : verse;

return [{
  json: {
    lesson_file: webhook.lesson_file,
    lesson_content: webhook.lesson_content || '',
    title: webhook.title,
    verse_id: webhook.verse_id,
    verse_number: verseData.verse_number,
    sanskrit: verseData.sanskrit,
    english_translation: verseData.english_translation,
    theme: verseData.theme
  }
}];

values.content:
=Given this lesson:

Title: {{ $json.title }}
Verse: {{ $json.verse_number }} ({{ $json.theme }})
Sanskrit: {{ $json.sanskrit }}
Translation: {{ $json.english_translation }}

Lesson content:
{{ $json.lesson_content }}

---

Extract and create three social media adaptations:

1. "quote_card": The single most powerful sentence from this lesson.
   { "text": "<the quote>", "attribution": "Vivekachudamani, Verse {{ $json.verse_number }}" }

2. "reel_script": A 30-45 second reel script.
   { "hook": "<pattern-interrupt opening, under 10 words>", "segments": [{"text": "...", "duration_s": 5, "visual": "description of what viewer sees"}], "cta": "<call to action>", "total_duration_s": 40 }

3. "twitter_thread": A 4-6 tweet thread that unpacks the lesson.
   { "tweets": ["1/ ...", "2/ ...", "3/ ...", "4/ ..."] }

Output as a single JSON object with keys: quote_card, reel_script, twitter_thread

