// Parse Claude response and create separate items for each content type
const claudeOutput = $input.first().json;
let content;

try {
  const text = claudeOutput.text || claudeOutput.message?.content?.[0]?.text || JSON.stringify(claudeOutput);
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  content = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse Claude response: ${e.message}`);
}

const lesson = $('Merge Lesson + Verse').first().json;

return [
  {
    json: {
      type: 'quote_card',
      verse_id: lesson.verse_id,
      verse_number: lesson.verse_number,
      content: content.quote_card,
      source_lesson: lesson.lesson_file
    }
  },
  {
    json: {
      type: 'reel_script',
      verse_id: lesson.verse_id,
      verse_number: lesson.verse_number,
      content: content.reel_script,
      source_lesson: lesson.lesson_file
    }
  },
  {
    json: {
      type: 'twitter_thread',
      verse_id: lesson.verse_id,
      verse_number: lesson.verse_number,
      content: content.twitter_thread,
      source_lesson: lesson.lesson_file
    }
  }
];

// Generate CMO-LOG entry
const items = $input.all();
const lesson = $('Merge Lesson + Verse').first().json;
const now = new Date().toISOString();

const logEntry = `\n## ${now.split('T')[0]} - Social Adaptation\n\n` +
  `- **Source**: ${lesson.lesson_file}\n` +
  `- **Verse**: #${lesson.verse_number} (${lesson.theme})\n` +
  `- **Generated**: quote_card, reel_script, twitter_thread\n` +
  `- **Status**: draft (awaiting review)\n` +
  `- **Timestamp**: ${now}\n`;

return [{ json: { log_entry: logEntry } }];

